/**
 * Shared utilities for sprinkles.
 */

/**
 * Type-safe property assignment helper for sprinkles objects.
 * Only assigns if value is defined, avoiding undefined assignments.
 *
 * @example
 * const props: StackSprinkles = {};
 * assignProp(props, "flexDirection", direction);
 * assignProp(props, "gap", gap);
 */
export function assignProp<T extends object, K extends keyof T>(
  target: T,
  key: K,
  value: T[K] | undefined
): void {
  if (value !== undefined) {
    target[key] = value;
  }
}
