/**
 * Shared responsive conditions for vanilla-extract sprinkles.
 * Reusable by any component that needs responsive sprinkles.
 */

import { breakpoints } from "@angi/one-design-system-tokens";

/**
 * Breakpoints excluded from sprinkles to reduce CSS bundle size.
 * - "2xs" (320px) is excluded because "base" already covers 0px+ and virtually
 *   no devices are under 320px, making it redundant.
 */
export const EXCLUDED_BREAKPOINTS = ["2xs"] as const;

type ExcludedBreakpoint = (typeof EXCLUDED_BREAKPOINTS)[number];
type IncludedBreakpoint = Exclude<keyof typeof breakpoints, ExcludedBreakpoint>;

type ResponsiveConditions = { base: Record<string, never> } & {
  [K in IncludedBreakpoint]: { "@media": string };
};

function buildResponsiveConditions(): ResponsiveConditions {
  const result: Record<string, { "@media": string } | Record<string, never>> = {
    base: {},
  };

  for (const [bp, value] of Object.entries(breakpoints)) {
    if (!EXCLUDED_BREAKPOINTS.includes(bp as ExcludedBreakpoint)) {
      result[bp] = { "@media": `(min-width: ${value})` };
    }
  }

  return result as ResponsiveConditions;
}

/**
 * Responsive conditions for use with vanilla-extract defineProperties.
 * Includes "base" (no media query) plus breakpoints from tokens (excluding 2xs).
 */
export const responsiveConditions = buildResponsiveConditions();

/** Breakpoint keys available in sprinkles (excludes 2xs) */
export type SprinklesBreakpoint = "base" | IncludedBreakpoint;
