/**
 * Shared types for responsive sprinkles.
 * These types are used by both Stack and Box components.
 */

import { breakpoints, spacing } from "@angi/one-design-system-tokens";
import { EXCLUDED_BREAKPOINTS, type SprinklesBreakpoint } from "./conditions";

// ═══════════════════════════════════════════════════════════════════════════════
// SHARED TYPES
// ═══════════════════════════════════════════════════════════════════════════════

/**
 * Breakpoint keys available in sprinkles.
 * Re-exported from conditions.ts for convenience.
 * Note: "2xs" is excluded to reduce CSS bundle size.
 */
export type Breakpoint = SprinklesBreakpoint;

/** Spacing token keys */
export type SpacingKey = keyof typeof spacing;

/** Margin values include "auto" for centering */
export type MarginValue = SpacingKey | "auto";

/** A value that can be static or responsive (per-breakpoint) */
export type Responsive<T> = T | Partial<Record<Breakpoint, T>>;

// ═══════════════════════════════════════════════════════════════════════════════
// CONFIG ARRAYS (derived from tokens - single source of truth)
// ═══════════════════════════════════════════════════════════════════════════════

/** All breakpoint keys available in sprinkles (derived from tokens, excludes "2xs") */
export const BreakpointKeys = [
  "base",
  ...Object.keys(breakpoints).filter(
    (bp) =>
      !EXCLUDED_BREAKPOINTS.includes(
        bp as (typeof EXCLUDED_BREAKPOINTS)[number]
      )
  ),
] as Breakpoint[];

/** All spacing keys from tokens */
export const SpacingKeys = Object.keys(spacing) as SpacingKey[];

/** All margin values (spacing keys + "auto") */
export const MarginValues = [...SpacingKeys, "auto"] as const;
